// ============================================================
// Required fixes for EF Core 9 Cosmos DB provider (separate project)
// Apply these changes to your Cosmos DB DbContext.
// ============================================================

using Microsoft.EntityFrameworkCore;

// BREAKING CHANGE 1: Discriminator property renamed from "Discriminator" to "$type".
// Existing documents use "Discriminator" — explicitly configure to preserve compatibility.
//
// BREAKING CHANGE 2: id property no longer embeds the discriminator.
// Existing docs have format "EntityType|KeyValue" — opt in to preserve old format.
//
// BREAKING CHANGE 3: Synchronous I/O (ToList, SaveChanges, etc.) now throws.
// Replace all sync calls with async equivalents.

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix 1: Keep old discriminator property name for existing documents
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // Fix 2: Preserve old compound id format ("Session|123") for existing documents
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session { public string Id { get; set; } = default!; public string Name { get; set; } = default!; }

// Fix 3: Replace synchronous queries with async equivalents
class CosmosQueryService
{
    private readonly CosmosDbContext _db;
    public CosmosQueryService(CosmosDbContext db) => _db = db;

    // BEFORE (throws in EF Core 9):
    // var sessions = _db.Sessions.Where(s => s.Name == name).ToList();
    // _db.SaveChanges();

    // AFTER:
    public async Task<List<Session>> GetSessionsAsync(string name)
    {
        return await _db.Sessions.Where(s => s.Name == name).ToListAsync();
    }

    public async Task SaveAsync()
    {
        await _db.SaveChangesAsync();
    }
}

